        .strip_prefix("$VNRRG,07,")
        .or_else(|| line.strip_prefix("$VNWRG,07,"))?;
    let freq = body.split('*').next()?;
    freq.trim().parse().ok()
}

struct Config {
    port: String,
    baud: u32,
}

enum Command {
    Get,
    Set { hz: u32, persist: bool },
}

fn print_usage() {
    eprint!(
        "Usage:\n  \
         rdwr_vn100 [--port PORT] [--baud BAUD] get\n  \
         rdwr_vn100 [--port PORT] [--baud BAUD] set <HZ> [--persist]\n\n\
         Defaults: --port /dev/ttyUSB0  --baud 115200\n\
         Valid HZ: {VALID_RATES:?}\n"
    );
}

/// Parse CLI args into a connection config and a command.
fn parse_args<I: Iterator<Item = String>>(args: I) -> Result<(Config, Command), String> {
    let mut port = "/dev/ttyUSB0".to_string();
    let mut baud = 115_200u32;
    let mut persist = false;
    let mut positional: Vec<String> = Vec::new();

    let mut args = args.peekable();
    while let Some(arg) = args.next() {
        match arg.as_str() {
            "--port" => port = args.next().ok_or("--port requires a value")?,
            "--baud" => {
                baud = args
                    .next()
                    .ok_or("--baud requires a value")?
                    .parse()
                    .map_err(|_| "--baud must be a number")?
            }
            "--persist" => persist = true,
            _ => positional.push(arg),
        }
    }

    let command = match positional.first().map(String::as_str) {
        Some("get") => {
            if persist {
                return Err("--persist only applies to `set`".into());
            }
            Command::Get
        }
        Some("set") => {
            let hz: u32 = positional
                .get(1)
                .ok_or("set requires a frequency, e.g. `set 40`")?
                .parse()
                .map_err(|_| "frequency must be a number")?;
            if !VALID_RATES.contains(&hz) {
                return Err(format!("{hz} Hz is not valid; choose one of {VALID_RATES:?}"));
            }
            Command::Set { hz, persist }
        }
        Some(other) => return Err(format!("unknown command `{other}`")),
        None => return Err("missing command (`get` or `set`)".into()),
    };

    Ok((Config { port, baud }, command))
}

/// Read lines from the device until `matches` accepts one, or we give up.
/// Returns the matching line, or `None` on timeout/EOF.
fn read_reply<R, F>(reader: &mut R, mut matches: F) -> std::io::Result<Option<String>>
where
    R: BufRead,
    F: FnMut(&str) -> bool,
{
    for _ in 0..50 {
        let mut line = String::new();
        if reader.read_line(&mut line)? == 0 {
            return Ok(None); // timeout / EOF
        }
        let line = line.trim();
        if matches(line) {
            return Ok(Some(line.to_string()));
        }
    }
    Ok(None)
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let (config, command) = match parse_args(std::env::args().skip(1)) {
        Ok(parsed) => parsed,
        Err(e) => {
            eprintln!("error: {e}\n");
            print_usage();
            std::process::exit(2);
        }
    };

    println!("Opening {} at {} baud...", config.port, config.baud);
    let port = serialport::new(&config.port, config.baud)
        .timeout(Duration::from_millis(1000))
        .open()?;
    // Drive both reads and writes through the BufReader's inner port.
    let mut reader = BufReader::new(port);

    let (cmd, persist) = match command {
        Command::Get => (build_command("VNRRG,07"), false),
        Command::Set { hz, persist } => (build_command(&format!("VNWRG,07,{hz}")), persist),
    };

    // Send the get/set command and confirm the register-7 reply.
    print!("TX: {cmd}");
    reader.get_mut().write_all(cmd.as_bytes())?;
    reader.get_mut().flush()?;
    let reply = read_reply(&mut reader, |l| parse_reg07(l).is_some())?
        .ok_or("no $VN_RG,07 response received from device")?;
